import React, { useState, useEffect } from 'react';
import { MenuAlt1Icon, XIcon } from 'lucide-react';
import Link from 'next/link';

const Sidebar = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isNavbarMenuOpen, setIsNavbarMenuOpen] = useState(false);

  const handleSidebarToggle = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  const handleMenuToggle = () => {
    setIsNavbarMenuOpen(!isNavbarMenuOpen);
  };

  return (
    <div className="hidden lg:block z-20 h-screen w-64 bg-zinc-600 p-4 text-zinc-400 transition duration-300">
      <div className="flex justify-between items-center mb-4">
        <Link href="#" className="text-lg font-bold text-white">
          Canvas Creative
        </Link>
        <button onClick={handleSidebarToggle} className="text-zinc-400 hover:text-zinc-300">
          <XIcon size={20} />
        </button>
      </div>
      <ul className="space-y-4">
        <li className="px-2 py-1 rounded-md hover:bg-zinc-700 transition duration-300">
          <Link href="#" className="flex items-center gap-2 text-sm">
            <MenuAlt1Icon size={16} />
            Dashboard
          </Link>
        </li>
        <li className="px-2 py-1 rounded-md hover:bg-zinc-700 transition duration-300">
          <Link href="#" className="flex items-center gap-2 text-sm">
            <MenuAlt1Icon size={16} />
            Settings
          </Link>
        </li>
        <li className="px-2 py-1 rounded-md hover:bg-zinc-700 transition duration-300">
          <Link href="#" className="flex items-center gap-2 text-sm">
            <MenuAlt1Icon size={16} />
            Profile
          </Link>
        </li>
      </ul>
      <div className="flex justify-between items-center mt-4">
        <button onClick={handleMenuToggle} className="text-zinc-400 hover:text-zinc-300">
          <XIcon size={20} />
        </button>
        <button className="bg-zinc-600 py-2 px-4 rounded-md text-sm text-white hover:bg-zinc-700 transition duration-300">
          Logout
        </button>
      </div>
    </div>
  );
};

export default Sidebar;

