import React from 'react';
import { FaFacebookF, FaTwitter, FaInstagram, FaLinkedinIn } from 'lucide-react';

const Icon = ({ icon, size = 24 }) => {
  return (
    <div className="flex items-center justify-center w-8 h-8 text-zinc-400 rounded-full bg-zinc-600 hover:bg-zinc-700 transition duration-300">
      <FaFacebookF size={size} className="text-zinc-400" />
    </div>
  );
};

const NavigationTab = ({ children, active }) => {
  return (
    <div
      className={`flex items-center justify-center py-2 px-4 w-full rounded-md ${active ? 'bg-zinc-600' : 'bg-zinc-800'} hover:bg-zinc-700 transition duration-300`}
    >
      {children}
    </div>
  );
};

const NavigationLink = ({ href, children, active }) => {
  return (
    <a
      href={href}
      className={`flex items-center justify-center py-2 px-4 w-full rounded-md ${active ? 'bg-zinc-600' : 'bg-zinc-800'} hover:bg-zinc-700 transition duration-300`}
