          <div className="w-full md:w-1/2 lg:w-1/3 xl:w-1/3 p-4">
            <h6 className="text-lg font-bold text-zinc-400 mb-2">Quick Links</h6>
            <div className="flex flex-col md:flex-row">
              <NavigationTab active={true} onClick={handleMenuToggle}>
                <Icon icon={FaFacebookF} size={16} />
              </NavigationTab>
              <NavigationTab active={true} onClick={handleMenuToggle}>
                <Icon icon={FaTwitter} size={16} />
              </NavigationTab>
              <NavigationTab active={true} onClick={handleMenuToggle}>
                <Icon icon={FaInstagram} size={16} />
              </NavigationTab>
              <NavigationTab active={true} onClick={handleMenuToggle}>
                <Icon icon={FaLinkedinIn} size={16} />
              </NavigationTab>
